    (I_3x*t4dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - (I_3x*t5dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - (I_3y*t4dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 + (I_3y*t5dot^2*sin(2*t6 + 2*t7 + 2*t8 + 2*t9))/2 - I_3x*cos(2*t6 + 2*t7 + 2*t8 + 2*t9)*t4dot*t5dot + I_3y*cos(2*t6 + 2*t7 + 2*t8 + 2*t9)*t4dot*t5dot + (l_2*l_3*m_3*sin(t9)*t6dot^2)/2 + (l_2*l_3*m_3*sin(t9)*t7dot^2)/2 + (l_2*l_3*m_3*sin(t9)*t8dot^2)/2 + (l_3*lb*m_3*sin(t7 + t8 + t9)*t6dot^2)/4 + (l_1*l_3*m_3*sin(t8 + t9)*t6dot^2)/2 + (l_1*l_3*m_3*sin(t8 + t9)*t7dot^2)/2 + l_1*l_3*m_3*sin(t8 + t9)*t6dot*t7dot + l_2*l_3*m_3*sin(t9)*t6dot*t7dot + l_2*l_3*m_3*sin(t9)*t6dot*t8dot + l_2*l_3*m_3*sin(t9)*t7dot*t8dot];











%% define desired joint angles and rates
q_des = [-0.523599;0;0]; % J1 = 30 deg
q_des_dot =[0; 0; 0];

%% SMC Control joint torque limit
tau_max =[5;2.5;2.5];

%% Base inertia, coupled inertia and joint inertia and coriolis matrices derived from H and C_dphi
H_bb = H(1:6, 1:6);
H_bq = H(1:6, 7:9);
C_bb = C_dPhi(1:6);
H_qq = H(7:9, 7:9);
C_qq = C_dPhi(7:9);


%% Error and sliding surface
qe     = q - q_des;
qe_dot = q_dot - q_des_dot;
S      = qe_dot + lambda * qe;

%% Reduced-order dynamics (coupling-compensated)
H_q = H_qq - H_bq.' * (H_bb \ H_bq);   % use \ instead of pinv
C_q = C_qq - H_bq.' * (H_bb \ C_bb);

%% SMC control law
% q_des_ddot = 0 for rest-to-rest; add it if tracking a trajectory
tau_q_eqv = C_q + H_q * (- lambda * qe_dot);   % corrected
tau_q_sw  = -H_q * (Ks .* min(max(S ./ phi_s, -1), 1));

tau_joint = tau_q_eqv + tau_q_sw;
tau_q     = min(max(tau_joint, -tau_max), tau_max);



tau =[0; 0; 0; 0; 0; 0; tau_q];


% Compute accelerations
ddPhi = H \ (tau - C_dPhi);
dPhidt = [dPhi; ddPhi];

disp(t);
end